import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { createSet } from "../../../../../lib/questions/create_set.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    const { name, category, amount, userId } = await req.json();
    if (!userId || amount === undefined) return new Response(JSON.stringify({ error: "Missing userId or amount" }), { status: 400 });

    const setId = await createSet(supabase, name, category, amount, userId);
    return new Response(JSON.stringify({ setId }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});
